query NetworkingResources {
  module(name: "networking") {
    resources {
      id
      shortName
      resourceType
    }
  }
}

query VpcAttributes {
  resource(id: "module.networking.null_resource.vpc") {
    id
    attributes
    tags
  }
}

query FindBastion {
  resources(module: "compute", limit: 50) {
    nodes {
      id
      shortName
      resourceType
    }
  }
}

query BastionAttributes {
  resource(id: "module.compute.null_resource.bastion") {
    id
    shortName
    attributes
  }
}

query InfraSummary {
  summary {
    totalResources
    totalModules
    moduleNames
    typeBreakdown { resourceType count }
  }
}

query DatabaseModule {
  module(name: "database") {
    name
    resourceCount
    resources { id shortName resourceType }
  }
}

